#include <iostream>

int main() {
    constexpr int FACTOR{ 9 };
    constexpr int DIVISOR{ 5 };
    constexpr int OFFSET{ 32 };
    int raw{};
    std::cin >> raw;
    const int celsius{ raw };
    int fahrenheit{ celsius * FACTOR / DIVISOR + OFFSET };
    std::cout << "F: " << fahrenheit << '\n';
    return 0;
}

