solution_code:
#include <iostream>
#include <string>
#include <string_view>

std::string_view classify(std::string_view word) {
    if (word.starts_with("hello"))
        return "greeting";
    if (word.starts_with("bye"))
        return "farewell";
    return "unknown";
}

int main() {
    std::string word{};
    std::cin >> word;
    std::cout << classify(word) << '\n';
    return 0;
}
